import sys
import json


def validate_config(path):
    """Validate config file at the given path."""
    try:
        with open(path, 'r') as f:
            config = json.load(f)
    except FileNotFoundError:
        print(f"Error: File not found: {path}", file=sys.stderr)
        sys.exit(1)
    except json.JSONDecodeError as e:
        print(f"Error: Invalid JSON format: {e}", file=sys.stderr)
        sys.exit(1)

    required_fields = {'workers', 'shards', 'timeout', 'max_retries'}
    missing_fields = required_fields - set(config.keys())
    if missing_fields:
        print(f"Error: Missing required fields: {', '.join(sorted(missing_fields))}", file=sys.stderr)
        sys.exit(1)

    try:
        workers = config['workers']
        if not isinstance(workers, int) or workers <= 0:
            print("Error: 'workers' must be a positive integer", file=sys.stderr)
            sys.exit(1)

        shards = config['shards']
        if not isinstance(shards, int) or shards <= 0:
            print("Error: 'shards' must be a positive integer", file=sys.stderr)
            sys.exit(1)

        timeout = config['timeout']
        if not isinstance(timeout, (int, float)) or timeout <= 0:
            print("Error: 'timeout' must be a positive number", file=sys.stderr)
            sys.exit(1)

        max_retries = config['max_retries']
        if not isinstance(max_retries, int) or max_retries < 0:
            print("Error: 'max_retries' must be a non-negative integer", file=sys.stderr)
            sys.exit(1)

        print("Config validation passed")
        sys.exit(0)

    except (KeyError, TypeError) as e:
        print(f"Error: Invalid config structure: {e}", file=sys.stderr)
        sys.exit(1)


def main():
    if len(sys.argv) != 2:
        print("Usage: configlint.py <config_file>", file=sys.stderr)
        sys.exit(1)

    config_path = sys.argv[1]
    validate_config(config_path)


if __name__ == "__main__":
