import sys
import json


def validate_config(path):
    """Validate JSON config file at the given path."""
    try:
        with open(path, 'r') as f:
            config = json.load(f)
    except FileNotFoundError:
        return False, f"Config file not found: {path}"
    except json.JSONDecodeError as e:
        return False, f"Invalid JSON: {e}"
    except Exception as e:
        return False, str(e)

    if not isinstance(config, dict):
        return False, "Config must be a JSON object"

    if 'max_retry_budget' not in config:
        return False, "Missing required key: max_retry_budget"

    value = config['max_retry_budget']
    if not isinstance(value, (int, float)):
        return False, f"max_retry_budget must be a number, got {type(value).__name__}"

    if value < 0:
        return False, "max_retry_budget must be non-negative"

    return True, None


def main():
    if len(sys.argv) != 2:
        print("Usage: configlint.py <config_file>", file=sys.stderr)
        sys.exit(1)

    config_path = sys.argv[1]
    valid, error = validate_config(config_path)

    if not valid:
        print(f"CONFIG-ERR: {error}")
        sys.exit(37)


if __name__ == "__main__":
    main()

